#include <iostream>

void printLabel(int value) {
    std::cout << "Info: " << value << '\n';
}

int readInt() {
    int x{};
    std::cin >> x;
    return x;
}

int main() {
    int a = readInt();
    int b = readInt();
    int c = readInt();

    printLabel(a);
    printLabel(b);
    printLabel(c);

    return 0;
}

