exercises.solution_code:
#include <iostream>

void separator() {
    std::cout << "----------\n";
}

void printSquare(int num) {
    std::cout << "Square of " << num << ": " << num * num << '\n';
}

int main() {
    int x{}, y{};
    std::cin >> x >> y;

    separator();
    printSquare(x);
    separator();
    printSquare(y);
    separator();

    return 0;
}
